### 任务 4: 日志安全增强 (P1 - 重要)

**优先级**: 🟠 高  
**预计工作量**: 1 天

**实施方案**:

```typescript
// src/dashboard/utils/logger.ts
import pino from 'pino';

const SENSITIVE_PATTERNS = [
  /password/i,
  /token/i,
  /secret/i,
  /api[_-]?key/i,
  /authorization/i
];

function redactSensitive(data: any): any {
  if (typeof data === 'string') {
    return SENSITIVE_PATTERNS.reduce((acc, pattern) => {
      return acc.replace(pattern, '[REDACTED]');
    }, data);
  }

  if (typeof data === 'object' && data !== null) {
    const redacted = Array.isArray(data) ? [] : {};
    for (const [key, value] of Object.entries(data)) {
      if (SENSITIVE_PATTERNS.some(p => p.test(key))) {
        redacted[key] = '[REDACTED]';
      } else {
        redacted[key] = redactSensitive(value);
      }
    }
    return redacted;
  }

  return data;
}

export const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
  formatters: {
    log: (object) => redactSensitive(object)
  }
});
```

