```typescript
/**
 * 安全工具函数
 */

/**
 * 转义 Shell 参数，防止命令注入
 */
export function escapeShellArg(arg: string): string {
  // 移除或转义危险字符
  return arg
    .replace(/'/g, "'\"'\"'")  // 转义单引号
    .replace(/\\/g, '\\\\')     // 转义反斜杠
    .replace(/\n/g, '')         // 移除换行
    .replace(/\r/g, '')         // 移除回车
    .substring(0, 100);         // 限制长度
}

/**
 * 验证文件路径，防止路径遍历
 */
export function validateFilePath(filePath: string, basePath: string): boolean {
  const resolved = path.resolve(basePath, filePath);
  return resolved.startsWith(path.resolve(basePath));
}

/**
 * 创建安全的临时文件
 */
export async function createSecureTempFile(prefix: string): Promise<string> {
  const tmpDir = path.join(os.tmpdir(), `ai-dev-${process.pid}`);
  await fs.promises.mkdir(tmpDir, { 
    recursive: true, 
    mode: 0o700  // 仅用户可访问
  });

  return path.join(tmpDir, `${prefix}-${Date.now()}.txt`);
}
```

