class SecureStorage {
  private static SECRET = process.env.VITE_STORAGE_SECRET || 'default-secret';

  static setItem(key: string, value: any): void {
    const encrypted = CryptoJS.AES.encrypt(
      JSON.stringify(value),
      this.SECRET
