**创建验证模块** (`src/middleware/validation.ts`):
```typescript
import { FastifyRequest, FastifyReply, RouteOptions } from 'fastify';
import { z, ZodSchema } from 'zod';

export function validateRequest<T extends ZodSchema>(schema: {
  body?: T;
  querystring?: T;
  params?: T;
}) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      if (schema.body) {
        request.body = schema.body.parse(request.body);
      }

      if (schema.querystring) {
        request.query = schema.querystring.parse(request.query);
      }

      if (schema.params) {
        request.params = schema.params.parse(request.params);
      }
    } catch (error: any) {
      reply.status(400).send({
        success: false,
        error: {
          code: 'VALIDATION_ERROR',
          message: 'Invalid request data',
          details: error.errors
        }
      });
      throw error;  // 阻止继续执行
    }
  };
}

// 使用示例
const createIterationSchema = {
  body: z.object({
    iterationNumber: z.number().int().positive(),
    status: z.enum(['pending', 'running', 'completed', 'failed']),
    requirement: z.string().min(10).max(1000)
  })
};

fastify.post('/iterations', {
